const sd = $getWorkflowStaticData('global');
const offset = sd.telegramOffset || 0;
return [{ json: { offset } }];

const data = $input.first().json;
const updates = data.result || [];

if (updates.length === 0) return [];

const sd = $getWorkflowStaticData('global');
const maxId = Math.max(...updates.map(u => u.update_id));
sd.telegramOffset = maxId + 1;

const relevant = [];
for (const update of updates) {
  if (update.callback_query) {
    const cq = update.callback_query;
    const callbackData = cq.data || '';
    const underscoreIdx = callbackData.indexOf('_');
    const action = underscoreIdx !== -1 ? callbackData.substring(0, underscoreIdx) : callbackData;
    const recordId = underscoreIdx !== -1 ? callbackData.substring(underscoreIdx + 1) : '';
    relevant.push({
      json: {
        type: 'callback',
        callbackData,
        callbackQueryId: cq.id,
        chatId: String(cq.message && cq.message.chat ? cq.message.chat.id : ''),
        action,
        recordId,
        messageText: ''
      }
    });
  } else if (update.message && update.message.text) {
    const msg = update.message;
    relevant.push({
      json: {
        type: 'message',
        callbackData: '',
        callbackQueryId: '',
        chatId: String(msg.chat ? msg.chat.id : ''),
        action: '',
        recordId: '',
        messageText: msg.text
      }
    });
  }
}

return relevant;

const record = $input.first().json;
const fields = record.fields || {};
const toEmail = fields.Afzender || '';
const subject = 'Re: ' + (fields.Onderwerp || '');
const draftText = fields.Concept || '';
const bodyHtml = draftText.replace(/\n/g, '<br>');
return [{ json: { toEmail, subject, bodyHtml, recordId: record.id } }];

const sd = $getWorkflowStaticData('global');
sd.pendingPaymentRecordId = $json.recordId;
